function parseOklchComponent(val: string, maxVal: number): number {
  if (!val) return 0;
  const clean = val.trim();
  if (clean.endsWith('%')) {
    return (parseFloat(clean) / 100) * maxVal;
  }
  return parseFloat(clean);
}

export function convertOklchStringToRgb(cssValue: string): string {
  if (typeof cssValue !== 'string') return cssValue;
  if (!cssValue.includes('oklch')) return cssValue;

  return cssValue.replace(/oklch\(\s*([0-9.]+%?)\s+([0-9.]+%?)\s+([0-9.]+(?:deg|grad|rad|turn)?)(?:\s*\/\s*([0-9.]+%?))?\s*\)/gi, (match, lStr, cStr, hStr, aStr) => {
    try {
      const l = parseOklchComponent(lStr, 1);
      const c = parseOklchComponent(cStr, 1);
      
      const hStrClean = hStr.trim();
      let h = parseFloat(hStrClean);
      if (hStrClean.endsWith('rad')) {
        h = (h * 180) / Math.PI;
      } else if (hStrClean.endsWith('grad')) {
        h = (h * 180) / 200;
      } else if (hStrClean.endsWith('turn')) {
        h = h * 360;
      }
      
      let alpha = 1;
      if (aStr) {
        const aStrClean = aStr.trim();
        if (aStrClean.endsWith('%')) {
          alpha = parseFloat(aStrClean) / 100;
        } else {
          alpha = parseFloat(aStrClean);
        }
      }

      const hRad = (h * Math.PI) / 180;
      const aSq = c * Math.cos(hRad);
      const bSq = c * Math.sin(hRad);
      
      const l_ = l + 0.3963377774 * aSq + 0.2158037573 * bSq;
      const m_ = l - 0.1055613458 * aSq - 0.0638541728 * bSq;
      const s_ = l - 0.0894841775 * aSq - 1.2914855480 * bSq;
      
      const l_cube = l_ * l_ * l_;
      const m_cube = m_ * m_ * m_;
      const s_cube = s_ * s_ * s_;
      
      let r = +4.0767416621 * l_cube - 3.3077115913 * m_cube + 0.2309699292 * s_cube;
      let g = -1.2684380046 * l_cube + 2.6097574011 * m_cube - 0.3413193965 * s_cube;
      let b = -0.0041960863 * l_cube - 0.7034186147 * m_cube + 1.7076147010 * s_cube;
      
      const gamma = (x: number) => (x <= 0.0031308 ? 12.92 * x : 1.055 * Math.pow(x, 1 / 2.4) - 0.055);
      
      r = Math.max(0, Math.min(1, r));
      g = Math.max(0, Math.min(1, g));
      b = Math.max(0, Math.min(1, b));
      
      const rFinal = Math.round(gamma(r) * 255);
      const gFinal = Math.round(gamma(g) * 255);
      const bFinal = Math.round(gamma(b) * 255);
      
      if (aStr !== undefined && aStr !== null) {
        return `rgba(${rFinal}, ${gFinal}, ${bFinal}, ${alpha})`;
      }
      return `rgb(${rFinal}, ${gFinal}, ${bFinal})`;
    } catch {
      return 'rgba(255, 255, 255, 1)';
    }
  });
}

