  // --- High-Fidelity Custom Notification (Toast) System ---
  const [toasts, setToasts] = useState<{ id: string; message: string; type: 'info' | 'success' | 'warning' }[]>([]);

  const addToast = (message: string, type: 'info' | 'success' | 'warning' = 'success') => {
    const id = Math.random().toString(36).substring(2, 9);
    setToasts((prev) => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts((prev) => prev.filter((t) => t.id !== id));
    }, 5500); // 5.5 seconds display
  };

  const alert = (msg: any) => {
    if (msg === undefined || msg === null) return;
    let strMsg = typeof msg === 'string' ? msg : '';
    if (!strMsg) {
      try {
        strMsg = JSON.stringify(msg);
      } catch {
        strMsg = String(msg);
      }
    }
    
    // Auto-detect best style based on message content
    let type: 'info' | 'success' | 'warning' = 'success';
    const lower = strMsg.toLowerCase();
    if (
      lower.includes('warning') || 
      lower.includes('error') || 
      lower.includes('empty') || 
      lower.includes('lacks') || 
      lower.includes('offline') || 
      lower.includes('cannot') || 
      lower.includes('must') || 
      lower.includes('restricted') || 
      lower.includes('exists') ||
      lower.includes('invalid') ||
      lower.includes('failed')
    ) {
      type = 'warning';
    } else if (
      lower.includes('notice') || 
      lower.includes('info') || 
      lower.includes('select') || 
      lower.includes('choose') ||
      lower.includes('please')
    ) {
      type = 'info';
    }
    addToast(strMsg, type);
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      isInitialMount.current = false;
    }, 1500);
    return () => clearTimeout(timer);
  }, []);

  // Banner Slider Index
  const [activeSlide, setActiveSlide] = useState(0);
  
