  const [ca1Max, setCa1Max] = useState<number>(() => {
    const saved = localStorage.getItem('gja_ca1_max');
    if (saved !== null) return Number(saved);
    const m = (localStorage.getItem('gja_ca_mode') || '2-ca');
    return m === '3-ca' ? 10 : 15;
  });

  const [ca2Max, setCa2Max] = useState<number>(() => {
    const saved = localStorage.getItem('gja_ca2_max');
    if (saved !== null) return Number(saved);
    const m = (localStorage.getItem('gja_ca_mode') || '2-ca');
    return m === '3-ca' ? 10 : 15;
  });

