  const [scoresheetSelectedTerm, setScoresheetSelectedTerm] = useState<'1st Term' | '2nd Term' | '3rd Term'>('1st Term');
  const [scoresheetSelectedClass, setScoresheetSelectedClass] = useState(() => classesDb.length > 0 ? classesDb[0] : 'Grade 1');
  const printAsBlankScoresheet = true;
  const [activePrintLayout, setActivePrintLayout] = useState<'report-card' | 'broadsheet' | 'scratch-cards' | 'audit-report' | 'invoice' | 'scoresheet' | 'session-leaders' | 'admission-offer' | 'admission-profile' | null>(null);
  const [offerToPrint, setOfferToPrint] = useState<any>(null);
  const [profileToPrint, setProfileToPrint] = useState<any>(null);

  const [scoresheetIsGeneratingPdf, setScoresheetIsGeneratingPdf] = useState(false);
  const [pdfGenerationProgress, setPdfGenerationProgress] = useState(0);

  const downloadScoresheetsAsPdf = async () => {
    const targetTutor = teachersDb.find(t => t.id === scoresheetSelectedTeacherId) || teachersDb[0];
    if (!targetTutor) return;

    setScoresheetIsGeneratingPdf(true);
    setPdfGenerationProgress(0);

    try {
      // 1. Show the print layout synchronously so it renders in the DOM
      flushSync(() => {
        setActivePrintLayout('scoresheet');
      });

      // 2. Allow DOM to render and images to layout
      await new Promise(resolve => setTimeout(resolve, 350));

      const printableElement = document.getElementById('printable-single-scoresheet');
      if (!printableElement) {
        throw new Error("Printable scoresheet element not found in DOM");
      }

      // Query for children divs that represent pages
      const pageElements = Array.from(printableElement.children).filter(el => el.tagName === 'DIV') as HTMLElement[];

      if (pageElements.length === 0) {
        throw new Error("No pages found to generate PDF");
      }

      // Initialize jsPDF (A4 portrait size, pt unit)
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'pt',
        format: 'a4'
      });

      const originalGetComputedStyle = window.getComputedStyle;
      // Wrap computed style queries to transparently map Tailwind v4 oklch colors into standard RGB format for html2canvas
      window.getComputedStyle = function (elt, pseudoElt) {
        const style = originalGetComputedStyle.call(window, elt, pseudoElt);
        return new Proxy(style, {
          get(target, prop) {
            // Read directly from target to avoid passing the proxy wrapper as 'this' context to native getters
            const val = target[prop as any];
            if (typeof val === 'function') {
              if (prop === 'getPropertyValue') {
                return function(propertyName: string) {
                  const rawValue = target.getPropertyValue(propertyName);
                  return convertOklchStringToRgb(rawValue);
                };
              }
              return val.bind(target);
            }
            if (typeof val === 'string' && val.includes('oklch')) {
              return convertOklchStringToRgb(val);
            }
            return val;
          }
        });
      };

      try {
        for (let i = 0; i < pageElements.length; i++) {
          setPdfGenerationProgress(Math.round((i / pageElements.length) * 100));
          const pageEl = pageElements[i];

          // Capture each page's canvas
          const canvas = await html2canvas(pageEl, {
            scale: 1.5,
            useCORS: true,
            allowTaint: true,
            logging: true,
            backgroundColor: '#ffffff'
          });

          const imgData = canvas.toDataURL('image/jpeg', 0.95);
          const imgWidth = pdf.internal.pageSize.getWidth();
          const imgHeight = (canvas.height * imgWidth) / canvas.width;

          if (i > 0) {
            pdf.addPage();
          }

          // Add to pdf fitting into page dimensions
          pdf.addImage(imgData, 'JPEG', 0, 0, imgWidth, imgHeight);
        }
      } finally {
        window.getComputedStyle = originalGetComputedStyle;
      }

      setPdfGenerationProgress(100);
      pdf.save(`${targetTutor.name.replace(/\s+/g, '_')}_Scoresheets_${scoresheetSelectedTerm.replace(' ', '')}.pdf`);
    } catch (err) {
      console.error("Failed to generate scoresheets PDF: ", err);
      alert("Error generating PDF: " + (err instanceof Error ? err.message : String(err)));
    } finally {
      // Reset layout visibility back to normal
      flushSync(() => {
        setActivePrintLayout(null);
      });
      // Delay reset state slightly for smoother UI transitions
      setTimeout(() => {
        setScoresheetIsGeneratingPdf(false);
      }, 500);
    }
  };

