  // Midnight Manifest Auto-Refresh Effect
  useEffect(() => {
    const checkMidnightAndReset = () => {
      const now = new Date();
      // Format as YYYY-MM-DD local style
      const localDateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
      const savedDate = localStorage.getItem('gja_last_manifest_refresh') || '';

      if (savedDate && savedDate !== localDateStr) {
        // A new day has begun! Save prior snapshot to archive if it contains boarders to keep record
        const currentRosterJson = localStorage.getItem('gja_bus_roster');
        let currentRoster: any[] = [];
        try {
          currentRoster = currentRosterJson ? JSON.parse(currentRosterJson) : [];
        } catch (e) {
          console.error(e);
        }

        if (currentRoster.length > 0) {
          const historyJson = localStorage.getItem('gja_manifest_history') || '[]';
          let historyList = [];
          try {
            historyList = JSON.parse(historyJson);
          } catch (e) {
            console.error(e);
          }

          // Avoid duplicate entries for the same date
          if (!historyList.some((h: any) => h.date === savedDate)) {
            historyList.push({
              id: 'manifest-' + savedDate + '-' + Date.now(),
              date: savedDate,
              roster: currentRoster,
              savedAt: new Date().toISOString()
            });
            localStorage.setItem('gja_manifest_history', JSON.stringify(historyList));
            setManifestHistory(historyList);
          }
        }

        // Reset active daily statuses back to "Assigned"
        const resetRoster = currentRoster.map((r: any) => ({ ...r, status: 'Assigned' }));
        localStorage.setItem('gja_bus_roster', JSON.stringify(resetRoster));
        localStorage.setItem('gja_last_manifest_refresh', localDateStr);

        setBusRoster(resetRoster);
        setLastManifestRefreshDate(localDateStr);
        alert(`🔔 Auto-Notification: Standard Midnight Refresh Processed. Prior day's transit manifest (${savedDate}) is saved securely to the archive, and today's statuses are reset to 'Assigned'.`);
      } else if (!savedDate) {
        localStorage.setItem('gja_last_manifest_refresh', localDateStr);
        setLastManifestRefreshDate(localDateStr);
      }
    };

    checkMidnightAndReset();
    // Check every fifteen seconds
    const intervalId = setInterval(checkMidnightAndReset, 15000);
    return () => clearInterval(intervalId);
  }, [busRoster]);

  // Dynamic broadsheet computations
  const getBroadsheetData = () => {
    const classStudents = studentsDb.filter(s => s.grade === broadsheetSelectedClass);
    // Find unique subjects in this class - restricted to configured class subjects
    const configuredSubjects = classSubjectsDb[broadsheetSelectedClass];
    const subjects = (configuredSubjects && configuredSubjects.length > 0)
      ? [...configuredSubjects]
      : Array.from(new Set(classStudents.flatMap(s => (((s.termResults as any)[broadsheetSelectedTerm])?.subjects || []).map((sub: any) => sub.name)))) as string[];
    
    // Sort subjects alphabetically for consistent columns
    if (subjects.length === 0) {
      // Fallback
      subjects.push("Mathematics & Logic");
    }
    subjects.sort();

    // Map students with their scores
    const studentsWithTotals = classStudents.map(student => {
      const termData = (student.termResults as any)[broadsheetSelectedTerm] || { subjects: [] };
      let total = 0;
      let count = 0;
      
      const subjectScores = subjects.reduce((acc, subName) => {
        const matchingSub = termData.subjects?.find((s: any) => s.name === subName);
        if (matchingSub) {
          const score = matchingSub.score || 0;
          total += score;
          count++;
          acc[subName] = score;
        } else {
          acc[subName] = null;
        }
        return acc;
      }, {} as Record<string, number | null>);

      return {
        id: student.id,
        name: student.name,
        subjectScores,
        total,
        average: count > 0 ? (total / count).toFixed(1) : "0.0",
        count
      };
    });

    // Rank students by total score descending
    const ranked = [...studentsWithTotals].sort((a, b) => b.total - a.total);
    const rankedStudents = studentsWithTotals.map(s => {
      const rankIdx = ranked.findIndex(r => r.id === s.id);
      let pos = "N/A";
      if (rankIdx >= 0) {
        const num = rankIdx + 1;
        const lastDigit = num % 10;
        const lastTwoDigits = num % 100;
        if (lastTwoDigits >= 11 && lastTwoDigits <= 13) {
          pos = `${num}th`;
        } else if (lastDigit === 1) {
          pos = `${num}st`;
        } else if (lastDigit === 2) {
          pos = `${num}nd`;
        } else if (lastDigit === 3) {
          pos = `${num}rd`;
        } else {
          pos = `${num}th`;
        }
      }
      return {
        ...s,
        position: pos
      };
    });

    return {
      subjects,
      students: rankedStudents
    };
  };

  const handleDownloadScoresheetCSV = (subjectName: string, tutorName: string, matchingStudents: any[]) => {
    const headers = ["S/N", "Student ID", "Student Name", "CA 1 (15)", "CA 2 (15)", ...(caMode === '3-ca' ? ["CA 3 (10)"] : []), "Exam Score"];
    let csv = `"${schoolSettings.name || 'GRACELAND JUNIOR ACADEMY'}"\n`;
    csv += `"Continuous Assessment Scoresheet - ${subjectName}"\n`;
    csv += `"Tutor: ${tutorName} • Term: ${scoresheetSelectedTerm}"\n\n`;
    csv += headers.map(h => `"${h}"`).join(",") + "\n";
    
    matchingStudents.forEach((std, idx) => {
      const subData = (((std.termResults as any)[scoresheetSelectedTerm] || {}).subjects || []).find((s: any) => s.name === subjectName) || {};
      const row = [
        idx + 1,
        std.id,
        std.name,
        subData.ca1 || 0,
        subData.ca2 || 0,
        ...(caMode === '3-ca' ? [subData.ca3 || 0] : []),
        subData.exam || 0
      ];
      csv += row.map(v => `"${v}"`).join(",") + "\n";
    });

    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", `Scoresheet_${subjectName.replace(/ /g, '_')}_${scoresheetSelectedTerm.replace(/ /g, '_')}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

