  const handleCSVUpload = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result as string;
      const lines = text.split(/\r?\n/);
      if (lines.length < 2) {
        alert("The selected CSV file appears to be empty or lacks headers.");
        return;
      }
      
      const headers = lines[0].split(',').map(h => h.trim().replace(/^["']|["']$/g, '').toLowerCase());
      
      const nameIndex = headers.findIndex(h => h.includes('name'));
      const classIndex = headers.findIndex(h => h.includes('class') || h.includes('grade'));
      const regIndex = headers.findIndex(h => h.includes('reg') || h.includes('id') || h.includes('code') || h.includes('num'));
      const genderIndex = headers.findIndex(h => h.includes('gender') || h.includes('sex'));
      const dobIndex = headers.findIndex(h => h.includes('dob') || h.includes('birth') || h.includes('date'));
      
      if (nameIndex === -1) {
        alert("Unable to locate a student 'Name' column in the CSV file headers. Ensure the column contains 'name' in its title.");
        return;
      }

      const importedStudents: any[] = [];
      let skippedCount = 0;

      for (let i = 1; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;

        const rCells: string[] = [];
        let curCell = '';
        let insideQuotes = false;
        for (let charIdx = 0; charIdx < line.length; charIdx++) {
          const char = line[charIdx];
          if (char === '"' || char === "'") {
            insideQuotes = !insideQuotes;
          } else if (char === ',' && !insideQuotes) {
            rCells.push(curCell.trim().replace(/^["']|["']$/g, ''));
            curCell = '';
          } else {
            curCell += char;
          }
        }
        rCells.push(curCell.trim().replace(/^["']|["']$/g, ''));

        const rawName = rCells[nameIndex];
        if (!rawName) {
          skippedCount++;
          continue;
        }

        const studentName = rawName.trim();
        let targetCls = classIndex !== -1 ? rCells[classIndex] : '';
        if (targetCls) {
          const matchedClass = classesDb.find(c => c.toLowerCase() === targetCls.toLowerCase().trim() || c.toLowerCase().replace(/ /g, '') === targetCls.toLowerCase().replace(/ /g, ''));
          if (matchedClass) {
            targetCls = matchedClass;
          }
        }
        const finalClass = targetCls || newStudentClass;

        const cleanPrefix = schoolSettings.registrationPrefix.trim() || "GJA-";
        let regId = regIndex !== -1 ? rCells[regIndex] : '';
        if (!regId) {
          regId = `${cleanPrefix}2026-${Math.floor(100 + Math.random() * 899)}-${importedStudents.length + i}`;
        }

        const finalRegId = regId.trim();
        if (studentsDb.some(s => s.id === finalRegId) || importedStudents.some(s => s.id === finalRegId)) {
          skippedCount++;
          continue;
        }

        const gender = (genderIndex !== -1 && rCells[genderIndex]) ? rCells[genderIndex].trim() : 'Unspecified';
        const dob = (dobIndex !== -1 && rCells[dobIndex]) ? rCells[dobIndex].trim() : '';
        const rawPin = Math.floor(1000 + Math.random() * 9000).toString();

        const classSubjects = classSubjectsDb[finalClass] || subjectsDb;
        const dynamicClassFee = schoolSettings.classFees[finalClass] ?? 150000;

        importedStudents.push({
          id: finalRegId,
          pin: rawPin,
          name: studentName,
          grade: finalClass,
          registrationNo: finalRegId,
          gender: gender,
          dob: dob,
          termResults: {
            "1st Term": { gpa: "0.00", position: "N/A", attendance: "100%", teacherComments: "Welcome to academy. Initial curriculum assessment started.", subjects: classSubjects.map((n: string) => ({ name: n, score: 0, ca1: 0, ca2: 0, ca3: 0, exam: 0, grade: "F" })) },
            "2nd Term": { gpa: "0.00", position: "N/A", attendance: "100%", teacherComments: "Welcome to academy. Initial curriculum assessment started.", subjects: classSubjects.map((n: string) => ({ name: n, score: 0, ca1: 0, ca2: 0, ca3: 0, exam: 0, grade: "F" })) },
            "3rd Term": { gpa: "0.00", position: "N/A", attendance: "100%", teacherComments: "Welcome to academy. Initial curriculum assessment started.", subjects: classSubjects.map((n: string) => ({ name: n, score: 0, ca1: 0, ca2: 0, ca3: 0, exam: 0, grade: "F" })) }
          },
          fees: { totalDue: dynamicClassFee, totalPaid: 0, balance: dynamicClassFee }
        });
      }

      if (importedStudents.length > 0) {
        setStudentsDb(prev => [...prev, ...importedStudents]);
        alert(`Successfully uploaded, configured and enrolled ${importedStudents.length} student profiles via CSV batch import!${skippedCount > 0 ? ` Note: ${skippedCount} items were skipped due to duplication or missing parameters.` : ''}`);
      } else {
        alert("No new unique student profiles found in the CSV. Make sure student ID values are unique.");
      }
    };
    reader.readAsText(file);
  };

