  const handleVoidPaymentLog = (txn: any) => {
    const confirmMessage = `Are you absolutely sure you want to VOID transaction ${txn.txnId} of ${txn.amountPaid} for ${txn.studentName}? This will instantly restore their outstanding arrears and mark this transaction as Voided.`;

    setConfirmModal({
      isOpen: true,
      title: "Void Financial Entry",
      message: confirmMessage,
      actionLabel: "Yes, Void Entry",
      actionClassName: "bg-red-600 hover:bg-red-700 text-white font-extrabold py-2 px-4 rounded-xl text-xs transition cursor-pointer shadow-md shadow-red-200",
      onCallback: () => {
        // Parse amount to number
        const rawAmt = txn.amountPaid;
        const cleanAmt = typeof rawAmt === 'string' ? rawAmt.replace(/[^\d]/g, '') : (rawAmt ? String(rawAmt) : '0');
        const numericAmount = Number(cleanAmt);
        if (isNaN(numericAmount) || numericAmount <= 0) {
          setBursarFeedback("❌ Error: Cannot calculate void amount.");
          setTimeout(() => setBursarFeedback(''), 4500);
          return;
        }

        const cleanName = (name: string) => name.trim().replace(/\s+/g, ' ').toLowerCase();

        let studentFound = false;
        const updatedDb = studentsDb.map(student => {
          const isNameMatch = cleanName(student.name) === cleanName(txn.studentName);
          const isIdMatch = txn.studentId && student.id === txn.studentId;

          if (isIdMatch || isNameMatch) {
            const prevFees = student.fees || { totalDue: 150000, totalPaid: 0, balance: 150000 };
            const newPaid = Math.max(0, prevFees.totalPaid - numericAmount);
            const newBal = Math.max(0, prevFees.totalDue - newPaid);
            studentFound = true;
            return {
              ...student,
              fees: {
                ...prevFees,
                totalPaid: newPaid,
                balance: newBal
              }
            };
          }
          return student;
        });

        if (!studentFound) {
          setBursarFeedback("⚠️ Warning: Student account was not matched in the roster, but voiding transaction log anyway.");
          setTimeout(() => setBursarFeedback(''), 4500);
        }

        const updatedLogs = paymentLogs.map(log => {
          if (log.txnId === txn.txnId) {
            return {
              ...log,
              status: "Voided / Cancelled",
              datePaid: `${log.datePaid} (VOIDED / REVERSED)`
            };
          }
          return log;
        });

        setStudentsDb(updatedDb);
        setPaymentLogs(updatedLogs);
        localStorage.setItem('gja_students_db', JSON.stringify(updatedDb));
        localStorage.setItem('gja_payment_receipts', JSON.stringify(updatedLogs));

        setBursarFeedback(`⌫ Transaction ${txn.txnId} reversed. Outstanding balance restored.`);
        setTimeout(() => setBursarFeedback(''), 4500);
      }
    });
  };

