                                              {/* Grade letter */}
                                              <td className="py-3 px-3 text-center">
                                                <span className="font-extrabold bg-slate-900 text-white px-2 py-0.5 rounded text-[9px]">
                                                  {calculatedLettGrade}
                                                </span>
                                              </td>

                                              {/* Dynamic Subject Position Display */}
                                              <td className="py-3 px-3 text-center font-mono font-black text-indigo-700 bg-indigo-50/20">
                                                {dynamicSubjectPosition}
                                              </td>

                                              {/* Form comments list overall ONLY if active teacher is Form Master of the class */}
