                              // Find student
                              const std = studentsDb.find(s => s.id === assignBusStudentId);
                              if (!std) {
                                alert("Selected pupil record not found.");
                                return;
                              }
                              // Find route
                              const rt = schoolSettings.busRoutes?.find((r: any) => r.id === assignBusRouteId);
                              const rtZone = rt ? rt.route : "General Tour";

                              const basePrice = rt ? rt.price : 60000;
                              const isHalf = assignBusSchedule === 'morning' || assignBusSchedule === 'afternoon';
                              const finalFare = isHalf ? (basePrice / 2) : basePrice;

                              const newRider = {
                                id: "bus-" + Date.now(),
                                studentId: std.id,
                                studentName: std.name,
                                grade: std.grade || "Primary",
                                routeId: rt ? rt.id : assignBusRouteId,
                                routeZone: rtZone,
                                scheduleType: assignBusSchedule,
                                fare: finalFare,
                                status: "Assigned" as const,
                                emergencyPhone: assignBusEmergency || std.parentPhone || "N/A"
                              };

                              setBusRoster([...busRoster, newRider]);
                              setAssignBusStudentId('');
                              setAssignBusRouteId('');
                              setAssignBusEmergency('');
                              setPassengerStudentSearch('');
                              alert(`${std.name} has been successfully added to the bus transit roster!`);
